// processes the output with jq, and saves it to the specified file.
// Returns the stderr of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Construct the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create a pipe to connect the aliyun command's stdout to the jq command's stdin
	aliyunOut, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun: %w", err)
	}

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = aliyunOut

	// Set up the output file for jq
	output, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer output.Close()
	jqCmd.Stdout = output

	// Create buffers to capture stderr for both commands
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start the jq command first because it has to read from the pipe
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for the aliyun command to finish
	errAliyun := aliyunCmd.Wait()
	if errAliyun != nil {
		// If the aliyun command fails, kill the jq command because it will not get any input
		jqCmd.Process.Kill() // We kill the jq command
		// Wait for jq to exit and capture its stderr (if any)
		jqCmd.Wait() // We ignore the error from jq because we killed it
		// Combine the stderr from both commands
		combinedStderr := aliyunStderr.String() + jqStderr.String()
		return combinedStderr, fmt.Errorf("aliyun command failed: %w", errAliyun)
	}

	// Wait for the jq command to finish
	errJq := jqCmd.Wait()
	if errJq != nil {
		// Combine the stderr from both commands
		combinedStderr := aliyunStderr.String() + jqStderr.String()
		return combinedStderr, fmt.Errorf("jq command failed: %w", errJq)
	}

	// If we get here, both commands succeeded. We return the combined stderr (if any) and no error.
	combinedStderr := aliyunStderr.String() + jqStderr.String()
	return combinedStderr, nil
}

