package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	var stderr bytes.Buffer

	// Create output file
	f, err := os.Create(outputFile)
	if err != nil {
		return "", err
	}
	defer f.Close()

	// Create commands
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Pipe commands
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", err
	}
	cmd2.Stdin = pipe
	cmd2.Stdout = f

	// Capture stderr
	cmd1.Stderr = &stderr
	cmd2.Stderr = &stderr

	// Start commands
	if err := cmd1.Start(); err != nil {
		return stderr.String(), err
	}
	if err := cmd2.Start(); err != nil {
		cmd1.Wait()
		return stderr.String(), err
	}

	// Wait for commands
	err1 := cmd1.Wait()
	err2 := cmd2.Wait()

	if err1 != nil || err2 != nil {
		errMsg := ""
		if err1 != nil {
			errMsg += err1.Error()
		}
		if err2 != nil {
			if errMsg != "" {
				errMsg += "; "
			}
			errMsg += err2.Error()
		}
		return stderr.String(), fmt.Errorf("command errors: %s", errMsg)
	}

	return stderr.String(), nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: go run main.go <loadBalancerName> <outputFile>")
		os.Exit(1)
	}

	output, err := QuerySLBAndExport(os.Args[1], os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		fmt.Fprintf(os.Stderr, "Command output: %s\n", output)
		os.Exit(1)
	}

	fmt.Println("SLB data exported successfully")
	if output != "" {
		fmt.Println("Command output:", output)
	}
}

