import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stderr of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a pipe to connect the two commands
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("could not get stdout pipe for aliyun command: %w", err)
	}
	jqCmd.Stdin = pipe

	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("could not create output file: %w", err)
	}
	defer outFile.Close()

	// Set the stdout of jqCmd to the file
	jqCmd.Stdout = outFile

	// Capture stderr for both commands
	var aliyunStderr, jqStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start the aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("could not start aliyun command: %w", err)
	}

	// Start the jq command
	if err := jqCmd.Start(); err != nil {
		// If jq fails to start, kill the aliyun command
		aliyunCmd.Process.Kill()
		return "", fmt.Errorf("could not start jq command: %w", err)
	}

	// Wait for the aliyun command to finish
	errAliyun := aliyunCmd.Wait()

	// Wait for the jq command to finish
	errJq := jqCmd.Wait()

	// Combine the stderr from both commands
	combinedStderr := aliyunStderr.String() + jqStderr.String()

	// Check for errors
	if errAliyun != nil || errJq != nil {
		var errs []string
		if errAliyun != nil {
			errs = append(errs, errAliyun.Error())
		}
		if errJq != nil {
			errs = append(errs, errJq.Error())
		}
		errMsg := strings.Join(errs, "; ")
		return combinedStderr, fmt.Errorf("command failed: %s", errMsg)
	}

	return combinedStderr, nil
}

