import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the first command: aliyun
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	// Create the second command: jq
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect the stdout of cmd1 to the stdin of cmd2
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmd2.Stdin = pipe

	// Create buffers for stdout and stderr capture
	var stdoutBuf bytes.Buffer
	var stderr1, stderr2 bytes.Buffer
	cmd2.Stdout = &stdoutBuf
	cmd1.Stderr = &stderr1
	cmd2.Stderr = &stderr2

	// Start the first command
	if err := cmd1.Start(); err != nil {
		combinedStderr := append(stderr1.Bytes(), stderr2.Bytes()...)
		return string(combinedStderr), fmt.Errorf("command failed: %w, output: %s", err, string(combinedStderr))
	}

	// Start the second command
	if err := cmd2.Start(); err != nil {
		cmd1.Process.Kill()
		combinedStderr := append(stderr1.Bytes(), stderr2.Bytes()...)
		return string(combinedStderr), fmt.Errorf("command failed: %w, output: %s", err, string(combinedStderr))
	}

	// Wait for the first command to finish
	if err := cmd1.Wait(); err != nil {
		cmd2.Process.Kill()
		cmd2.Wait()
		combinedStderr := append(stderr1.Bytes(), stderr2.Bytes()...)
		return string(combinedStderr), fmt.Errorf("command failed: %w, output: %s", err, string(combinedStderr))
	}

	// Wait for the second command to finish
	if err := cmd2.Wait(); err != nil {
		combinedStderr := append(stderr1.Bytes(), stderr2.Bytes()...)
		return string(combinedStderr), fmt.Errorf("command failed: %w, output: %s", err, string(combinedStderr))
	}

	// Write the captured stdout to the output file
	if err := os.WriteFile(outputFile, stdoutBuf.Bytes(), 0644); err != nil {
		return stdoutBuf.String(), fmt.Errorf("failed to write output file: %w", err)
	}

	return stdoutBuf.String(), nil
}

