// processes the output with jq, and saves it to the specified file.
// Returns the stderr of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Create the commands
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Capture stderr for both commands
	var stderr1, stderr2 bytes.Buffer
	cmd1.Stderr = &stderr1
	cmd2.Stderr = &stderr2

	// Get the stdout pipe of the first command
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for first command: %w", err)
	}
	cmd2.Stdin = pipe
	cmd2.Stdout = outFile

	// Start the first command
	if err := cmd1.Start(); err != nil {
		return "", fmt.Errorf("failed to start first command: %w", err)
	}

	// Start the second command
	if err := cmd2.Start(); err != nil {
		cmd1.Process.Kill() // in case the first command is running
		return "", fmt.Errorf("failed to start second command: %w", err)
	}

	// Wait for the first command to finish
	err1 := cmd1.Wait()

	// Wait for the second command to finish
	err2 := cmd2.Wait()

	// Combine stderr
	stderr := stderr1.String() + stderr2.String()

	// Check for errors in either command
	if err1 != nil || err2 != nil {
		errMsg := ""
		if err1 != nil {
			errMsg += "first command error: " + err1.Error()
		}
		if err2 != nil {
			if errMsg != "" {
				errMsg += "; "
			}
			errMsg += "second command error: " + err2.Error()
		}
		return stderr, fmt.Errorf("pipeline failed: %s", errMsg)
	}

	return stderr, nil
}

