package main

import (
	"bytes"
	"context"
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
	"time"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the combined stderr output of both commands and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Basic input validation to prevent obvious shell injection
	if strings.ContainsAny(loadBalancerName, "`$\n\r\t|>") || strings.ContainsAny(outputFile, "`$\n\r\t|>") {
		return "", fmt.Errorf("invalid characters in input parameters")
	}

	// Create a context with a timeout of 55 seconds to prevent hanging.
	ctx, cancel := context.WithTimeout(context.Background(), 55*time.Second)
	defer cancel()

	// Create pipe to connect aliyun stdout to jq stdin
	pipeReader, pipeWriter := io.Pipe()
	defer pipeReader.Close()

	// Create output file
	file, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer file.Close()

	// Create aliyun command with context
	aliyunCmd := exec.CommandContext(ctx, "aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)
	aliyunCmd.Stdout = pipeWriter
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stderr = &aliyunStderr

	// Create jq command with context
	jqCmd := exec.CommandContext(ctx, "jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = pipeReader
	jqCmd.Stdout = file
	var jqStderr bytes.Buffer
	jqCmd.Stderr = &jqStderr

	// Start jq command first
	if err := jqCmd.Start(); err != nil {
		pipeWriter.Close()
		return aliyunStderr.String() + jqStderr.String(), fmt.Errorf("jq command start failed: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		pipeWriter.Close()
		jqCmd.Wait()
		return aliyunStderr.String() + jqStderr.String(), fmt.Errorf("aliyun command start failed: %w", err)
	}

	// Wait for aliyun command to finish, then close the pipeWriter to signal EOF to jq
	errAliyun := aliyunCmd.Wait()
	pipeWriter.Close() // Close the writer so jq gets EOF
	errJq := jqCmd.Wait()

	// Combine stderr outputs
	outputStr := aliyunStderr.String() + jqStderr.String()

	// Check for errors in either command
	if errAliyun != nil || errJq != nil {
		// If the context deadline was exceeded, return that error.
		if ctx.Err() == context.DeadlineExceeded {
			return outputStr, ctx.Err()
		}

		var errMsg strings.Builder
		if errAliyun != nil {
			errMsg.WriteString("aliyun: " + errAliyun.Error())
		}
		if errJq != nil {
			if errMsg.Len() > 0 {
				errMsg.WriteString("; ")
			}
			errMsg.WriteString("jq: " + errJq.Error())
		}
		return outputStr, fmt.Errorf("command pipeline failed: %s", errMsg.String())
	}

	return outputStr, nil
}

