import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stderr output of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Open the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Create the aliyun command
	cmd1 := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Get a pipe for the stdout of cmd1
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe for aliyun command: %w", err)
	}
	cmd2.Stdin = pipe

	// Set the stdout of cmd2 to the output file
	cmd2.Stdout = outFile

	// Create buffers for stderr of both commands
	var stderrBuffer1, stderrBuffer2 bytes.Buffer
	cmd1.Stderr = &stderrBuffer1
	cmd2.Stderr = &stderrBuffer2

	// Start the first command
	if err := cmd1.Start(); err != nil {
		return stderrBuffer1.String() + stderrBuffer2.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start the second command
	if err := cmd2.Start(); err != nil {
		return stderrBuffer1.String() + stderrBuffer2.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for the first command to finish
	err1 := cmd1.Wait()

	// Wait for the second command to finish
	err2 := cmd2.Wait()

	// Combine the stderr buffers
	combinedStderr := stderrBuffer1.String() + stderrBuffer2.String()

	// Check for errors in the commands
	if err1 != nil || err2 != nil {
		if err1 != nil && err2 != nil {
			return combinedStderr, fmt.Errorf("aliyun command failed: %v; jq command failed: %v", err1, err2)
		} else if err1 != nil {
			return combinedStderr, fmt.Errorf("aliyun command failed: %w", err1)
		} else {
			return combinedStderr, fmt.Errorf("jq command failed: %w", err2)
		}
	}

	return combinedStderr, nil
}

