package main

import (
	"bytes"
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stderr of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create buffers for stderr of both commands
	var stderrBuffer1, stderrBuffer2 bytes.Buffer

	// Create the aliyun command
	cmd1 := exec.Command(
		"aliyun",
		"slb",
		"DescribeLoadBalancers",
		"--LoadBalancerName",
		loadBalancerName,
	)
	cmd1.Stderr = &stderrBuffer1

	// Create the jq command
	cmd2 := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	cmd2.Stderr = &stderrBuffer2

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Pipe commands: cmd1 -> cmd2 -> outFile
	pipe, err := cmd1.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stdout pipe: %w", err)
	}
	cmd2.Stdin = pipe
	cmd2.Stdout = outFile

	// Start first command
	if err := cmd1.Start(); err != nil {
		return stderrBuffer1.String(), fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Start second command
	if err := cmd2.Start(); err != nil {
		cmd1.Process.Kill()
		return stderrBuffer1.String() + stderrBuffer2.String(), fmt.Errorf("failed to start jq command: %w", err)
	}

	// Wait for both commands to finish
	err1 := cmd1.Wait()
	err2 := cmd2.Wait()

	// Combine stderr outputs
	stderrCombined := stderrBuffer1.String() + stderrBuffer2.String()

	// Handle command errors
	switch {
	case err1 != nil:
		return stderrCombined, fmt.Errorf("aliyun command failed: %w", err1)
	case err2 != nil:
		return stderrCombined, fmt.Errorf("jq command failed: %w", err2)
	default:
		return stderrCombined, nil
	}
}

